"use client";

import { useState } from "react";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import {
  faPlus, faArrowUp, faArrowDown, faXmark,
  faCheck, faSpinner, faStar, faUsers,
  faTableCells, faList,
} from "@fortawesome/free-solid-svg-icons";
import { saveDefaultLineup, applyLineupToGame } from "@/server/actions/lineup";
import type { FieldingPosition } from "@prisma/client";

const POSITIONS: { value: FieldingPosition; short: string; label: string }[] = [
  { value: "PITCHER",      short: "P",  label: "Pitcher"      },
  { value: "CATCHER",      short: "C",  label: "Catcher"      },
  { value: "FIRST_BASE",   short: "1B", label: "First Base"   },
  { value: "SECOND_BASE",  short: "2B", label: "Second Base"  },
  { value: "THIRD_BASE",   short: "3B", label: "Third Base"   },
  { value: "SHORTSTOP",    short: "SS", label: "Shortstop"    },
  { value: "LEFT_FIELD",   short: "LF", label: "Left Field"   },
  { value: "CENTER_FIELD", short: "CF", label: "Center Field" },
  { value: "RIGHT_FIELD",  short: "RF", label: "Right Field"  },
  { value: "SHORT_FIELD",  short: "SF", label: "Short Field"  },
  { value: "EXTRA_PLAYER", short: "EP", label: "Extra Player" },
  { value: "BENCH",        short: "—",  label: "Bench"        },
];

const TOTAL_INNINGS = 7;

interface Player {
  id: string;
  firstName: string;
  lastName: string;
  jerseyNumber: string | null;
  primaryPosition: FieldingPosition;
  positions: FieldingPosition[];
}

interface LineupSlot {
  playerId: string;
  player: Player;
  battingOrder: number;
  fieldingPosition: FieldingPosition;
  inningPositions?: Record<number, FieldingPosition>;
}

interface Game {
  id: string;
  opponent: string;
  gameDate: Date;
}

interface LineupBuilderProps {
  players: Player[];
  games: Game[];
  defaultLineup: LineupSlot[];
}

type LineupMode = "standard" | "by-inning";

function getPlayerPositions(player: Player): FieldingPosition[] {
  return player.positions?.length > 0
    ? player.positions
    : POSITIONS.map((p) => p.value);
}

function InningGrid({
  lineup,
  inning,
  onUpdate,
}: {
  lineup: LineupSlot[];
  inning: number;
  onUpdate: (playerId: string, inning: number, pos: FieldingPosition) => void;
}) {
  const counts: Record<string, number> = {};
  lineup.forEach((s) => {
    const pos = s.inningPositions?.[inning] ?? s.fieldingPosition;
    if (pos !== "BENCH") counts[pos] = (counts[pos] ?? 0) + 1;
  });

  if (lineup.length === 0) {
    return (
      <div className="card py-12 text-center">
        <p style={{ color: "var(--color-text-muted)", fontSize: "0.875rem", margin: 0 }}>
          Add players to the batting order first.
        </p>
      </div>
    );
  }

  return (
    <div className="card p-2">
      {lineup.map((slot, index) => {
        const currentPos = slot.inningPositions?.[inning] ?? slot.fieldingPosition;
        const isDupe = (counts[currentPos] ?? 0) > 1 && currentPos !== "BENCH";
        return (
          <div
            key={slot.playerId}
            className="mb-1 flex items-center gap-3 rounded-lg px-3 py-2.5"
            style={{
              background: isDupe ? "rgba(245,158,11,0.06)" : "rgba(255,255,255,0.03)",
              border: `1px solid ${isDupe ? "rgba(245,158,11,0.2)" : "transparent"}`,
            }}
          >
            <span style={{ fontFamily: "var(--font-display)", fontWeight: 900, fontSize: "1.1rem", color: "var(--color-text-brand)", width: 24, textAlign: "center", flexShrink: 0 }}>
              {index + 1}
            </span>
            <span style={{ fontFamily: "var(--font-mono)", fontSize: "0.75rem", color: "var(--color-text-muted)", width: 28, flexShrink: 0 }}>
              #{slot.player.jerseyNumber ?? "—"}
            </span>
            <span style={{ flex: 1, fontSize: "0.875rem", fontWeight: 600, color: "#eeeef5", fontFamily: "var(--font-body)" }}>
              {slot.player.firstName} {slot.player.lastName}
            </span>
            <select
              value={currentPos}
              onChange={(e) => onUpdate(slot.playerId, inning, e.target.value as FieldingPosition)}
              style={{
                background: isDupe ? "rgba(245,158,11,0.1)" : "rgba(255,255,255,0.06)",
                border: `1px solid ${isDupe ? "rgba(245,158,11,0.3)" : "rgba(255,255,255,0.12)"}`,
                color: isDupe ? "#f59e0b" : "#eeeef5",
                borderRadius: 6, padding: "4px 6px",
                fontFamily: "var(--font-mono)", fontSize: "0.75rem",
                fontWeight: 700, cursor: "pointer", width: 52,
              }}
            >
              {POSITIONS.filter((p) => getPlayerPositions(slot.player).includes(p.value)).map((p) => (
                <option key={p.value} value={p.value} style={{ background: "#111125", color: "#eeeef5" }}>
                  {p.short}
                </option>
              ))}
            </select>
          </div>
        );
      })}
    </div>
  );
}

export function LineupBuilder({ players, games, defaultLineup }: LineupBuilderProps) {
  const [lineup, setLineup]             = useState<LineupSlot[]>(defaultLineup);
  const [mode, setMode]                 = useState<LineupMode>("standard");
  const [activeInning, setActiveInning] = useState(1);
  const [saving, setSaving]             = useState(false);
  const [applying, setApplying]         = useState(false);
  const [savedMsg, setSavedMsg]         = useState("");
  const [selectedGameId, setSelectedGameId] = useState<string>("");

  const inLineup = new Set(lineup.map((s) => s.playerId));
  const bench    = players.filter((p) => !inLineup.has(p.id));

  const addToLineup = (player: Player) => {
    setLineup((prev) => [...prev, {
      playerId: player.id, player,
      battingOrder: prev.length + 1,
      fieldingPosition: player.primaryPosition,
      inningPositions: {},
    }]);
  };

  const removeFromLineup = (playerId: string) => {
    setLineup((prev) =>
      prev.filter((s) => s.playerId !== playerId)
        .map((s, i) => ({ ...s, battingOrder: i + 1 }))
    );
  };

  const moveUp = (index: number) => {
    if (index === 0) return;
    setLineup((prev) => {
      const next = [...prev];
      [next[index - 1], next[index]] = [next[index]!, next[index - 1]!];
      return next.map((s, i) => ({ ...s, battingOrder: i + 1 }));
    });
  };

  const moveDown = (index: number) => {
    if (index === lineup.length - 1) return;
    setLineup((prev) => {
      const next = [...prev];
      [next[index], next[index + 1]] = [next[index + 1]!, next[index]!];
      return next.map((s, i) => ({ ...s, battingOrder: i + 1 }));
    });
  };

  const updatePosition = (playerId: string, pos: FieldingPosition) => {
    setLineup((prev) => prev.map((s) => s.playerId === playerId ? { ...s, fieldingPosition: pos } : s));
  };

  const updateInningPosition = (playerId: string, inning: number, pos: FieldingPosition) => {
    setLineup((prev) => prev.map((s) =>
      s.playerId === playerId
        ? { ...s, inningPositions: { ...(s.inningPositions ?? {}), [inning]: pos } }
        : s
    ));
  };

  const copyInningForward = (fromInning: number) => {
    setLineup((prev) => prev.map((s) => {
      const sourcePos = s.inningPositions?.[fromInning] ?? s.fieldingPosition;
      const updated = { ...(s.inningPositions ?? {}) };
      for (let i = fromInning + 1; i <= TOTAL_INNINGS; i++) updated[i] = sourcePos;
      return { ...s, inningPositions: updated };
    }));
  };

  const handleSaveDefault = async () => {
    setSaving(true);
    await saveDefaultLineup(lineup.map((s) => ({
      playerId: s.playerId, battingOrder: s.battingOrder,
      fieldingPosition: s.fieldingPosition, inningPositions: s.inningPositions,
    })));
    setSaving(false);
    setSavedMsg("Default lineup saved!");
    setTimeout(() => setSavedMsg(""), 2500);
  };

  const handleApplyToGame = async () => {
    if (!selectedGameId) return;
    setApplying(true);
    await applyLineupToGame(selectedGameId, lineup.map((s) => ({
      playerId: s.playerId, battingOrder: s.battingOrder,
      fieldingPosition: s.fieldingPosition, inningPositions: s.inningPositions,
    })));
    setApplying(false);
    setSavedMsg("Lineup applied to game!");
    setTimeout(() => setSavedMsg(""), 2500);
  };

  const positionCounts: Record<string, number> = {};
  lineup.forEach((s) => {
    if (s.fieldingPosition !== "BENCH")
      positionCounts[s.fieldingPosition] = (positionCounts[s.fieldingPosition] ?? 0) + 1;
  });
  const hasDuplicates = Object.values(positionCounts).some((c) => c > 1);

  return (
    <div>
      {/* Mode toggle */}
      <div className="mb-6 flex items-center gap-3">
        <span style={{ fontSize: "0.8rem", fontWeight: 600, color: "var(--color-text-muted)", fontFamily: "var(--font-body)" }}>
          Position mode:
        </span>
        <div className="flex rounded-lg p-1" style={{ background: "var(--color-surface-card)", border: "1px solid var(--color-border-subtle)" }}>
          {([
            { value: "standard",  label: "Standard",  icon: faList },
            { value: "by-inning", label: "By Inning", icon: faTableCells },
          ] as const).map((m) => (
            <button key={m.value} onClick={() => setMode(m.value)}
              className="flex items-center gap-2 rounded-md px-4 py-1.5 text-sm font-semibold transition-all"
              style={{
                background: mode === m.value ? "var(--color-text-brand)" : "transparent",
                color: mode === m.value ? "#000" : "var(--color-text-muted)",
                border: "none", cursor: "pointer", fontFamily: "var(--font-body)",
              }}
            >
              <FontAwesomeIcon icon={m.icon} style={{ width: 12, height: 12 }} />
              {m.label}
            </button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 gap-6 lg:grid-cols-3">

        {/* Bench */}
        <div>
          <div className="eyebrow mb-3 flex items-center gap-2">
            <FontAwesomeIcon icon={faUsers} style={{ width: 12, height: 12 }} />
            Bench · {bench.length}
          </div>
          {bench.length === 0 ? (
            <div className="card py-8 text-center">
              <p style={{ color: "var(--color-text-muted)", fontSize: "0.875rem", margin: 0 }}>All players are in the lineup!</p>
            </div>
          ) : (
            <div className="card p-2">
              {bench.map((player) => (
                <div key={player.id}
                  className="flex items-center gap-3 rounded-lg px-3 py-2.5 transition-colors hover:bg-white/5"
                  style={{ cursor: "pointer" }}
                  onClick={() => addToLineup(player)}
                >
                  <span style={{ fontFamily: "var(--font-mono)", fontSize: "0.75rem", color: "var(--color-text-muted)", width: 28, flexShrink: 0 }}>
                    #{player.jerseyNumber ?? "—"}
                  </span>
                  <span style={{ flex: 1, fontSize: "0.875rem", fontWeight: 500, color: "#eeeef5" }}>
                    {player.firstName} {player.lastName}
                  </span>
                  <span style={{ fontFamily: "var(--font-mono)", fontSize: "0.7rem", fontWeight: 700, color: "var(--color-text-muted)", background: "rgba(255,255,255,0.06)", padding: "2px 8px", borderRadius: 4 }}>
                    {POSITIONS.find((p) => p.value === player.primaryPosition)?.short ?? "—"}
                  </span>
                  <FontAwesomeIcon icon={faPlus} style={{ width: 12, height: 12, color: "var(--color-text-brand)", flexShrink: 0 }} />
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Right panel */}
        <div className="lg:col-span-2">

          {/* Standard mode */}
          {mode === "standard" && (
            <>
              <div className="mb-3 flex items-center justify-between">
                <div className="eyebrow">Batting Order · {lineup.length}</div>
                {hasDuplicates && (
                  <span style={{ fontSize: "0.75rem", fontWeight: 600, color: "#f59e0b", background: "rgba(245,158,11,0.12)", border: "1px solid rgba(245,158,11,0.3)", padding: "2px 10px", borderRadius: 6 }}>
                    ⚠ Duplicate positions
                  </span>
                )}
              </div>

              {lineup.length === 0 ? (
                <div className="card py-12 text-center">
                  <p style={{ color: "var(--color-text-muted)", fontSize: "0.875rem", margin: 0 }}>Click players on the bench to add them.</p>
                </div>
              ) : (
                <div className="card p-2">
                  {lineup.map((slot, index) => {
                    const isDupe = (positionCounts[slot.fieldingPosition] ?? 0) > 1 && slot.fieldingPosition !== "BENCH";
                    return (
                      <div key={slot.playerId} className="mb-1 flex items-center gap-3 rounded-lg px-3 py-2"
                        style={{ background: isDupe ? "rgba(245,158,11,0.06)" : "rgba(255,255,255,0.03)", border: `1px solid ${isDupe ? "rgba(245,158,11,0.2)" : "transparent"}` }}>
                        <span style={{ fontFamily: "var(--font-display)", fontWeight: 900, fontSize: "1.25rem", color: "var(--color-text-brand)", width: 28, textAlign: "center", flexShrink: 0 }}>
                          {index + 1}
                        </span>
                        <span style={{ fontFamily: "var(--font-mono)", fontSize: "0.75rem", color: "var(--color-text-muted)", width: 28, flexShrink: 0 }}>
                          #{slot.player.jerseyNumber ?? "—"}
                        </span>
                        <span style={{ flex: 1, fontSize: "0.875rem", fontWeight: 600, color: "#eeeef5", fontFamily: "var(--font-body)" }}>
                          {slot.player.firstName} {slot.player.lastName}
                        </span>
                        <select value={slot.fieldingPosition}
                          onChange={(e) => updatePosition(slot.playerId, e.target.value as FieldingPosition)}
                          style={{ background: isDupe ? "rgba(245,158,11,0.1)" : "rgba(255,255,255,0.06)", border: `1px solid ${isDupe ? "rgba(245,158,11,0.3)" : "rgba(255,255,255,0.12)"}`, color: isDupe ? "#f59e0b" : "#eeeef5", borderRadius: 6, padding: "3px 6px", fontFamily: "var(--font-mono)", fontSize: "0.75rem", fontWeight: 700, cursor: "pointer", width: 52 }}>
                          {POSITIONS.filter((p) => getPlayerPositions(slot.player).includes(p.value)).map((p) => (
                            <option key={p.value} value={p.value} style={{ background: "#111125", color: "#eeeef5" }}>{p.short}</option>
                          ))}
                        </select>
                        <div className="flex gap-1">
                          <button onClick={() => moveUp(index)} disabled={index === 0}
                            style={{ background: "none", border: "none", cursor: index === 0 ? "default" : "pointer", color: index === 0 ? "rgba(255,255,255,0.15)" : "rgba(238,238,245,0.5)", padding: "4px 6px", borderRadius: 6 }}>
                            <FontAwesomeIcon icon={faArrowUp} style={{ width: 12, height: 12 }} />
                          </button>
                          <button onClick={() => moveDown(index)} disabled={index === lineup.length - 1}
                            style={{ background: "none", border: "none", cursor: index === lineup.length - 1 ? "default" : "pointer", color: index === lineup.length - 1 ? "rgba(255,255,255,0.15)" : "rgba(238,238,245,0.5)", padding: "4px 6px", borderRadius: 6 }}>
                            <FontAwesomeIcon icon={faArrowDown} style={{ width: 12, height: 12 }} />
                          </button>
                        </div>
                        <button onClick={() => removeFromLineup(slot.playerId)}
                          style={{ background: "none", border: "none", cursor: "pointer", color: "rgba(238,238,245,0.3)", padding: "4px 6px", borderRadius: 6 }}>
                          <FontAwesomeIcon icon={faXmark} style={{ width: 12, height: 12 }} />
                        </button>
                      </div>
                    );
                  })}
                </div>
              )}
            </>
          )}

          {/* By-inning mode */}
          {mode === "by-inning" && (
            <>
              <div className="mb-3 flex items-center justify-between">
                <div className="eyebrow">Positions by Inning</div>
                {lineup.length > 0 && activeInning < TOTAL_INNINGS && (
                  <button onClick={() => copyInningForward(activeInning)}
                    style={{ background: "rgba(255,255,255,0.06)", color: "#eeeef5", border: "1px solid rgba(255,255,255,0.12)", borderRadius: 6, padding: "4px 12px", fontSize: "0.75rem", fontWeight: 600, cursor: "pointer", fontFamily: "var(--font-body)" }}>
                    Copy inning {activeInning} → remaining
                  </button>
                )}
              </div>

              {/* Inning tabs */}
              <div className="mb-3 flex gap-1 overflow-x-auto pb-1">
                {Array.from({ length: TOTAL_INNINGS }, (_, i) => i + 1).map((inn) => {
                  const hasPositions = lineup.some((s) => s.inningPositions?.[inn]);
                  return (
                    <button key={inn} onClick={() => setActiveInning(inn)}
                      style={{
                        padding: "6px 14px", borderRadius: 8, border: "none",
                        background: activeInning === inn ? "var(--color-text-brand)" : hasPositions ? "rgba(0,232,122,0.1)" : "rgba(255,255,255,0.06)",
                        color: activeInning === inn ? "#000" : hasPositions ? "#00e87a" : "#eeeef5",
                        fontFamily: "var(--font-display)", fontWeight: 800, fontSize: "0.875rem",
                        cursor: "pointer", minWidth: 44, flexShrink: 0,
                        borderBottom: activeInning === inn ? "none" : hasPositions ? "2px solid rgba(0,232,122,0.3)" : "2px solid transparent",
                      }}
                    >
                      {inn}
                    </button>
                  );
                })}
              </div>

              <InningGrid lineup={lineup} inning={activeInning} onUpdate={updateInningPosition} />

              {/* Batting order collapsed */}
              <details className="mt-4">
                <summary style={{ cursor: "pointer", fontSize: "0.8rem", fontWeight: 600, color: "var(--color-text-muted)", fontFamily: "var(--font-body)", listStyle: "none", padding: "8px 0" }}>
                  ▸ Edit batting order ({lineup.length} players)
                </summary>
                <div className="card mt-2 p-2">
                  {lineup.map((slot, index) => (
                    <div key={slot.playerId} className="mb-1 flex items-center gap-3 rounded-lg px-3 py-2" style={{ background: "rgba(255,255,255,0.03)" }}>
                      <span style={{ fontFamily: "var(--font-display)", fontWeight: 900, fontSize: "1.1rem", color: "var(--color-text-brand)", width: 24, textAlign: "center" }}>{index + 1}</span>
                      <span style={{ fontFamily: "var(--font-mono)", fontSize: "0.75rem", color: "var(--color-text-muted)", width: 28 }}>#{slot.player.jerseyNumber ?? "—"}</span>
                      <span style={{ flex: 1, fontSize: "0.875rem", fontWeight: 600, color: "#eeeef5" }}>{slot.player.firstName} {slot.player.lastName}</span>
                      <div className="flex gap-1">
                        <button onClick={() => moveUp(index)} disabled={index === 0}
                          style={{ background: "none", border: "none", cursor: index === 0 ? "default" : "pointer", color: index === 0 ? "rgba(255,255,255,0.15)" : "rgba(238,238,245,0.5)", padding: "4px 6px" }}>
                          <FontAwesomeIcon icon={faArrowUp} style={{ width: 11, height: 11 }} />
                        </button>
                        <button onClick={() => moveDown(index)} disabled={index === lineup.length - 1}
                          style={{ background: "none", border: "none", cursor: index === lineup.length - 1 ? "default" : "pointer", color: index === lineup.length - 1 ? "rgba(255,255,255,0.15)" : "rgba(238,238,245,0.5)", padding: "4px 6px" }}>
                          <FontAwesomeIcon icon={faArrowDown} style={{ width: 11, height: 11 }} />
                        </button>
                      </div>
                      <button onClick={() => removeFromLineup(slot.playerId)}
                        style={{ background: "none", border: "none", cursor: "pointer", color: "rgba(238,238,245,0.3)", padding: "4px 6px" }}>
                        <FontAwesomeIcon icon={faXmark} style={{ width: 11, height: 11 }} />
                      </button>
                    </div>
                  ))}
                </div>
              </details>
            </>
          )}

          {/* Save actions */}
          {lineup.length > 0 && (
            <div className="mt-4 space-y-3">
              <div className="flex items-center gap-3">
                <button onClick={handleSaveDefault} disabled={saving}
                  className="flex items-center gap-2 rounded-lg px-5 py-2.5 font-bold transition-opacity hover:opacity-80 disabled:opacity-50"
                  style={{ background: "var(--color-text-brand)", color: "#000", fontFamily: "var(--font-display)", fontSize: "0.9rem", letterSpacing: "0.05em", border: "none", cursor: "pointer" }}>
                  {saving ? <FontAwesomeIcon icon={faSpinner} spin style={{ width: 14, height: 14 }} /> : <FontAwesomeIcon icon={faStar} style={{ width: 14, height: 14 }} />}
                  SAVE AS DEFAULT
                </button>
                <span style={{ fontSize: "0.75rem", color: "var(--color-text-muted)" }}>Auto-loads for new games</span>
              </div>

              {games.length > 0 && (
                <div className="rounded-[14px] p-4" style={{ background: "var(--color-surface-card)", border: "1px solid var(--color-border-subtle)" }}>
                  <div className="field-label mb-2">Apply to a specific game</div>
                  <div className="flex gap-3">
                    <select value={selectedGameId} onChange={(e) => setSelectedGameId(e.target.value)}
                      className="input" style={{ flex: 1, background: "var(--color-surface-card2)", color: selectedGameId ? "#eeeef5" : "rgba(238,238,245,0.4)", cursor: "pointer" }}>
                      <option value="" style={{ background: "#111125", color: "rgba(238,238,245,0.4)" }}>Select a game…</option>
                      {games.map((g) => (
                        <option key={g.id} value={g.id} style={{ background: "#111125", color: "#eeeef5" }}>
                          vs {g.opponent} — {new Date(g.gameDate).toLocaleDateString("en-US", { month: "short", day: "numeric" })}
                        </option>
                      ))}
                    </select>
                    <button onClick={handleApplyToGame} disabled={applying || !selectedGameId}
                      className="flex items-center gap-2 rounded-lg px-4 py-2 font-bold transition-opacity hover:opacity-80 disabled:opacity-40"
                      style={{ background: "rgba(255,255,255,0.08)", color: "#eeeef5", fontFamily: "var(--font-display)", fontSize: "0.875rem", letterSpacing: "0.05em", border: "1px solid rgba(255,255,255,0.12)", cursor: "pointer", whiteSpace: "nowrap" }}>
                      {applying ? <FontAwesomeIcon icon={faSpinner} spin style={{ width: 13, height: 13 }} /> : <FontAwesomeIcon icon={faCheck} style={{ width: 13, height: 13 }} />}
                      APPLY
                    </button>
                  </div>
                </div>
              )}

              {savedMsg && (
                <div className="flex items-center gap-2 rounded-lg px-4 py-2.5 text-sm font-medium"
                  style={{ background: "rgba(0,232,122,0.1)", border: "1px solid rgba(0,232,122,0.3)", color: "#00e87a" }}>
                  <FontAwesomeIcon icon={faCheck} style={{ width: 13, height: 13 }} />
                  {savedMsg}
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
